mapper.select:
SELECT  FROM video

    status=1
    AND id < #{lastId}
    AND type=#{type}

ORDER BY id DESC LIMIT #{size}

SELECT  FROM video
WHERE status=1 AND type=#{type} AND id != #{excludeId}

    AND (

        FIND_IN_SET(#{t}, tags)

    )

ORDER BY (like_count + view_count*0.1) DESC
LIMIT #{size}

SELECT  FROM video
WHERE status=1 AND (title LIKE CONCAT('%',#{keyword},'%') OR content LIKE CONCAT('%',#{keyword},'%') OR tags LIKE CONCAT('%',#{keyword},'%'))
ORDER BY id DESC LIMIT #{offset}, #{size}
